module top_module(
	input[3:0] busin,
	input clk, clr, wa,
	output[3:0] addrout);reg[3:0] store;

	assign addrout= store;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@ (posedge clk or posedge dbg_halt)
	begin
		if(clr)
			store= 4'h0;
		else if(wa)
			store= busin;
	end
	endmodule
